from decimal import Decimal
from dataclasses import dataclass
from typing import Dict

# Price per million tokens (USD) — update when provider publishes new rates
MODEL_RATES: Dict[str, Dict[str, Decimal]] = {
    "claude-3-5-sonnet-20241022": {
        "input":  Decimal("3.00"),   # $3.00 per million input tokens
        "output": Decimal("15.00"),  # $15.00 per million output tokens
    },
    "claude-3-5-haiku-20241022": {
        "input":  Decimal("0.80"),
        "output": Decimal("4.00"),
    },
    "claude-3-opus-20240229": {
        "input":  Decimal("15.00"),
        "output": Decimal("75.00"),
    },
}

MILLION = Decimal("1_000_000")


@dataclass
class UsageRecord:
    model: str
    input_tokens: int
    output_tokens: int
    tags: Dict[str, str]

    def cost_usd(self) -> Decimal:
        rates = MODEL_RATES[self.model]
        input_cost  = Decimal(self.input_tokens)  / MILLION * rates["input"]
        output_cost = Decimal(self.output_tokens) / MILLION * rates["output"]
        return (input_cost + output_cost).quantize(Decimal("0.000001"))


# --- Example ---
record = UsageRecord(
    model="claude-3-5-sonnet-20241022",
    input_tokens=1240,
    output_tokens=380,
    tags={"team": "payments", "feature": "fraud-check"},
)
print(f"Cost: ${record.cost_usd()}")  # Cost: $0.009420

from decimal import Decimal
from typing import Dict

def proportional_split(
    total_cost: Decimal,
    team_token_counts: Dict[str, int],
) -> Dict[str, Decimal]:
    total_tokens = sum(team_token_counts.values())
    if total_tokens == 0:
        return {team: Decimal("0") for team in team_token_counts}
    return {
        team: (total_cost * Decimal(count) / Decimal(total_tokens)).quantize(Decimal("0.01"))
        for team, count in team_token_counts.items()
    }

# Example: shared summarisation agent, $120 total cost
costs = proportional_split(
    total_cost=Decimal("120.00"),
    team_token_counts={"payments": 40000, "risk": 30000, "cx": 30000},
)
# {'payments': Decimal('48.00'), 'risk': Decimal('36.00'), 'cx': Decimal('36.00')}
